    Priority               => 5;
    Dispatch_Protocol      => Periodic;
    Period                 => 80 ms;
    Compute_Execution_Time => 0 ms .. 4 ms;
    Source_Stack_Size      => 512 Bytes;
  annex agree {**
    assume "signal_flow_x": acc_out_data_x = acc_in_data_x;
    assume "signal_flow_y": acc_out_data_y = acc_in_data_y;
    assume "signal_flow_z": acc_out_data_z = acc_in_data_z;
    guarantee "data_consistency_x": acc_out_data_x = acc_in_data_x;
    guarantee "data_consistency_y": acc_out_data_y = acc_in_data_y;
